import os
import sys

class SimpleShell:
    def __init__(self):
        self.commands = {
            "help": self.cmd_help,
            "cd": self.cmd_cd,
            "ls": self.cmd_ls,
            "pwd": self.cmd_pwd,
            "echo": self.cmd_echo,
            "exit": self.cmd_exit
        }

    def parse_input(self, user_input):
        """Parse user command into command and arguments"""
        parts = user_input.strip().split()
        if not parts:
            return None, []
        return parts[0], parts[1:]

    def cmd_help(self, args):
        """Display available commands"""
        print("Available commands: help, cd, ls, pwd, echo, exit")

    def cmd_cd(self, args):
        """Change directory - demonstrates system call access"""
        if not args:
            print("Usage: cd <directory>")
            return
        try:
            os.chdir(args[0])
            print(f"Changed directory to: {os.getcwd()}")
        except FileNotFoundError:
            print(f"Error: Directory '{args[0]}' not found")

    def cmd_ls(self, args):
        """List files - demonstrates directory reading system call"""
        try:
            files = os.listdir(os.getcwd())
            for f in files:
                print(f)
        except OSError as e:
            print(f"Error: {e}")

    def cmd_pwd(self, args):
        """Print working directory"""
        print(os.getcwd())

    def cmd_echo(self, args):
        """Echo arguments to console"""
        print(" ".join(args))

    def cmd_exit(self, args):
        """Exit the shell"""
        print("Goodbye!")
        sys.exit(0)

    def run(self):
        """Main shell loop"""
        print("SimpleShell v1.0 - Type 'help' for commands")
        while True:
            try:
                user_input = input(f"{os.getcwd()}$ ")
                command, args = self.parse_input(user_input)
                if command in self.commands:
                    self.commands[command](args)
                elif command:
                    print(f"Command not found: {command}")
            except KeyboardInterrupt:
                print("\nUse 'exit' to quit")
            except EOFError:
                print("\nGoodbye!")
                break

# Run the shell
if __name__ == "__main__":
    shell = SimpleShell()
    shell.run()
